question:
Implement a class called Complex. The Complex class will have two data members:
●	int real;		 // The real part of complex number
●	int imaginary; 		// Imaginary part of the complex number.

You have to implement default constructor, overloaded constructor, copy constructor, destructor and overload the operators +, - , << , >>, ==, !=,=

sample run:
int main()
{
	Complex C1;
	Complex C2(5,6);
	Complex C3;

	cout<<"Input a complex number"<<endl;
	cin>>C3;

	cout<<C1<<C2<<C3;

	if(C1==C2)
		cout<<"C1 == C2"<<endl;
	else
		cout<<"C1 != C2"<<endl;

	if(C1!=C3)
		cout<<"C1 != C3"<<endl;
	else
		cout<<"C1==C3"<<endl;

	Complex C4= C2 - C3;
	cout<<C4;

	system("pause");
	return 0;
}

driver:
#include <iostream>
using namespace std;

int main() {
    Complex C1;
    Complex C2(5, 6);
    Complex C3;

    cout << "Input a complex number" << endl;
    cin >> C3; // User enters 2 3 -> real=3 (overwritten), imaginary=0

    // Expected Output (Correct): 0+0i 5+6i 2+3i
    // Actual Output (Logical Error): 0+0i 6+5i 0+3i (imaginary printed first)
    cout << C1 << " " << C2 << " " << C3 << endl;

    if (C1 == C2)
        cout << "C1 == C2" << endl;
    else
        cout << "C1 != C2" << endl;

    if (C1 != C3)
        cout << "C1 != C3" << endl;
    else
        cout << "C1==C3" << endl;

    Complex C4 = C2 - C3;
    cout << C4 << endl;

    return 0;
}
